const elasticsearch = require('elasticsearch');

const client = new elasticsearch.Client({
  host: 'localhost:9200',
});

async function searchWithCustomScoring(params) {
  const { index, query, script } = params;

  const queryBody = {
    index: index,
    body: {
      query: {
        script_score: {
          query: query,
          script: {
            source: script,
            lang: 'painless',
          },
        },
      },
    },
  };

  const response = await client.search(queryBody);
  return response;
}

